body {
  font-family: "CustomFont", sans-serif;
  font-synthesis: none; /* Crucial for web fonts to prevent faux bold/italic */
}

/* Example of allowing specific synthesis if truly needed, though generally 'none' is best */
.legacy-content {
  font-synthesis: weight style; /* Allows synthesis for weight and style if original font lacks it */
}

:root {
  /* Fluid base font size: min 16px, preferred scales (1rem + 0.5vw), max 20px */
  font-size: clamp(16px, 1rem + 0.5vw, 20px);
}

h1 {
  /* Fluid H1 font size: min 40px, preferred scales (7vw + 1rem), max 80px */
  font-size: clamp(2.5rem, 7vw + 1rem, 5rem);
  line-height: 1.1;
}

p {
  /* Fluid paragraph font size: min 16px, preferred scales (1.5vw + 0.5rem), max 20px */
  font-size: clamp(1rem, 1.5vw + 0.5rem, 1.25rem);
}

h1,
.hero-subtitle,
.product-card-title {
  text-wrap: balance;
  /* Optimizes line breaks for visual balance, ideal for short text blocks. */
  /* Improves UI aesthetics by preventing awkward line lengths and orphans. */
}

@font-face {
  font-family: 'Inter UI';
  src: url('/fonts/Inter-Regular.woff2') format('woff2'),
       url('/fonts/Inter-Regular.woff') format('woff');
  font-weight: 400;
  font-style: normal;
  font-display: swap; /* Options: block, swap, fallback, optional */
}

h1 {
  font-family: "Playfair Display", serif; /* Example font supporting OpenType features */
  font-size: 2.8em;
  /* Enable discretionary ligatures ('dlig') and old-style numerals ('onum') */
  font-feature-settings: "dlig" 1, "onum" 1;
}

p {
  font-family: "Merriweather", serif;
  line-height: 1.6;
  /* Enable common ligatures ('liga') and small caps ('smcp') */
  font-feature-settings: "liga" 1, "smcp" 1;
}

/* Important: Ensure your chosen web fonts actually include these OpenType features. */

:root {
  --font-weight-base: 400;
  --font-width-base: 100;
}

body {
  font-family: "Inter var", sans-serif; /* Example variable font */
  font-variation-settings: 'wght' var(--font-weight-base), 'wdth' var(--font-width-base);
}

h1 {
  /* Dynamic weight and width for headings */
  font-variation-settings: 'wght' 700, 'wdth' 120;
}

@media (max-width: 768px) {
  h1 {
    /* Adjust for smaller screens to improve readability */
    font-variation-settings: 'wght' 600, 'wdth' 100;
  }
}

.hero-text {
  /* Apply optical size and a very bold weight for display text */
  font-variation-settings: 'wght' 850, 'opsz' 18;
  font-size: 3em;
}

/* Optimize for legibility on headings and larger text */
h1, .hero-text {
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased; /* Enhance macOS rendering */
  -moz-osx-font-smoothing: grayscale; /* Enhance macOS rendering */
}

/* Optimize for speed on body text or high-performance areas */
p, li {
  text-rendering: optimizeSpeed;
}

/* Restore default browser-dependent handling */
.default-behavior {
  text-rendering: auto;
}

@font-face {
  font-family: 'MyCustomFont';
  src: url('mycustomfont.woff2') format('woff2');
  font-display: swap; /* Use a display strategy that fits your needs */

  /* Tune these values to align with your fallback font's metrics */
  /* Example values; precise values require font analysis */
  size-adjust: 105%;    /* Adjusts the overall font size to match fallback */
  ascent-override: 95%; /* Adjusts the ascender height of the font */
  descent-override: 25%; /* Adjusts the descender height of the font */
  line-gap-override: 10%; /* Adjusts the line gap (leading) of the font */
}

body {
  font-family: 'MyCustomFont', serif; /* Ensure a suitable fallback */
  font-size: 1rem;
  line-height: 1.5;
}

:root {
  --base-font-size: 1rem; /* 16px */
  --base-line-height: 1.5; /* Multiplier for font-size, resulting in 24px for 16px font */
  --rhythm-unit: calc(var(--base-font-size) * var(--base-line-height)); /* Defines 24px as our fundamental vertical unit */
}

body {
  font-family: "Inter", sans-serif;
  font-size: var(--base-font-size);
  line-height: var(--base-line-height);
}

h1, h2, h3, h4, h5, h6, p, ul, ol, blockquote, figure {
  margin-top: var(--rhythm-unit);
  margin-bottom: var(--rhythm-unit);
}

/* Adjust top margin for the very first block on a page, or after non-text elements */
h1:first-child,
p:first-child,
.some-container > p:first-child {
  margin-top: 0;
}

/* Example: Use multiples of the rhythm unit for larger headings */
h2 {
  font-size: 2rem; /* e.g., 32px */
  margin-top: calc(var(--rhythm-unit) * 2); /* Double rhythm unit above h2 */
  margin-bottom: var(--rhythm-unit);
}

/* Smaller elements can use fractions of the rhythm unit */
.caption {
  font-size: 0.875rem; /* 14px */
  line-height: var(--base-line-height); /* Maintains same effective line-height in px as base */
  margin-top: calc(var(--rhythm-unit) / 2);
  margin-bottom: calc(var(--rhythm-unit) / 2);
}

a {
  text-decoration: underline; /* Ensure underline is present */
  text-decoration-color: var(--link-color, #007bff); /* Customize color */
  text-underline-offset: 0.2em; /* Lift underline off descenders for better readability */
  text-decoration-thickness: 1px; /* Control underline thickness for visual harmony */
  transition: text-decoration-color 0.3s ease, text-underline-offset 0.3s ease;
}

a:hover {
  text-decoration-color: var(--link-hover-color, #0056b3);
  text-underline-offset: 0.25em; /* Slightly lift more on hover for subtle feedback */
  text-decoration-thickness: 2px; /* Emphasize underline on hover */
}

/* Default spacing for body text */
body {
  font-family: 'Inter', sans-serif;
  letter-spacing: 0.01em; /* Small positive adjustment for readability */
  line-height: 1.6;
}

/* Tighter spacing for headlines/large text */
h1 {
  font-family: 'Lora', serif;
  font-size: 3em;
  letter-spacing: -0.02em; /* Slight negative adjustment */
  font-weight: 700;
}

/* Moderate spacing for smaller UI elements (e.g., buttons, tags) */
.button-text {
  font-family: 'Inter', sans-serif;
  font-size: 0.9em;
  letter-spacing: 0.03em; /* More pronounced positive adjustment for smaller caps/buttons */
  text-transform: uppercase;
  font-weight: 600;
}

/* Apply old-style proportional figures for body text */
.body-text {
  font-variant-numeric: old-style;
}

/* Ensure tabular lining figures for data display (e.g., tables, prices) */
.data-display {
  font-variant-numeric: tabular-nums lining-nums;
  /* Equivalent to font-feature-settings: "tnum", "lnum"; */
}

/* Use slashed zeros for clarity in code or data */
.code-block {
  font-variant-numeric: slashed-zero;
}

body {
